mapper.update:
UPDATE expense
SET amount = #{amount},
    description = #{description},
    year = #{year},
    month = #{month},
    day = #{day},
    version = version + 1
WHERE id = #{id}
  AND user_id = #{userId}
  AND version = #{version}

mapper.select:
SELECT 
    CASE 
        WHEN (
            (SELECT COALESCE(SUM(amount), 0) 
            FROM expense 
            WHERE budget_id = #{budgetId} 
            AND year = #{year} 
            AND month = #{month})
            + #{amount}
        ) > (SELECT amount FROM budget WHERE id = #{budgetId})
        THEN 1
        ELSE 0
    END AS overBudget

SELECT COUNT(*)
FROM expense
WHERE budget_id = #{budgetId}
